/**
 * Umožňuje nahrát a importovat slovník z RDF souboru (Turtle, JSON-LD). Soubor je validován a uložen do RDF úložiště. Vyžaduje autentizaci.
 * @summary Nahrání slovníku ze souboru
 */
export const uploadFromFile = (
  uploadFromFileBody: UploadFromFileBody,
  params?: UploadFromFileParams,
  options?: SecondParameter<typeof axiosInstance>,
  signal?: AbortSignal,
) => {
  const formData = new FormData();
  if (uploadFromFileBody.file !== undefined) {
    formData.append(`file`, uploadFromFileBody.file);
  }

  return axiosInstance<ApiResponseDtoOntologyMetadataModel>(
    {
      url: `/api/ontology/upload`,
      method: 'POST',
      headers: { 'Content-Type': 'multipart/form-data' },
      data: formData,
      params,
      signal,
    },
    options,
  );
};

